import type * as React from 'react';

import {cn} from '@/lib/utils';

import {ChevronDown} from 'lucide-react';

type NativeSelectProps = Omit<React.ComponentProps<'select'>, 'size'> & {
  size?: 'sm' | 'default';
};

/**
 * A styled native HTML select element with a custom chevron icon.
 *
 * ### Component Props
 *
 * Accepts all standard `<select>` HTML element props, plus:
 *
 * | Prop   | Type                  | Default     |
 * | :----- | :-------------------- | :---------- |
 * | _size_ | `"sm" \| "default"`   | `"default"` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <NativeSelect>
 *   <NativeSelectOption value="apple">Apple</NativeSelectOption>
 *   <NativeSelectOption value="banana">Banana</NativeSelectOption>
 * </NativeSelect>
 * ```
 */
function NativeSelect({
  className,
  size = 'default',
  ref,
  ...props
}: NativeSelectProps & {ref?: React.Ref<HTMLSelectElement>}) {
  return (
    <div
      className={cn(
        'group/native-select relative w-fit has-[select:disabled]:opacity-50',
        className
      )}
      data-slot="native-select-wrapper"
      data-size={size}
    >
      <select
        ref={ref}
        data-slot="native-select"
        data-size={size}
        className="h-9 w-full min-w-0 appearance-none rounded border border-input bg-transparent py-1 pr-8 pl-2.5 text-sm shadow-raised transition-[color,box-shadow] ease-default outline-none select-none selection:bg-primary selection:text-primary-foreground placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring disabled:pointer-events-none disabled:cursor-not-allowed aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 data-[size=sm]:h-8 dark:bg-input-bg dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 high-contrast:bg-input-bg high-contrast:placeholder:text-foreground"
        {...props}
      />
      <ChevronDown
        className="pointer-events-none absolute top-1/2 right-2.5 size-4 -translate-y-1/2 text-muted-foreground select-none"
        aria-hidden="true"
        data-slot="native-select-icon"
      />
    </div>
  );
}

/**
 * An option element for use within a `NativeSelect`.
 *
 * ### Component Props
 *
 * Accepts all standard `<option>` HTML element props.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <NativeSelectOption value="apple">Apple</NativeSelectOption>
 * ```
 */
function NativeSelectOption({...props}: React.ComponentProps<'option'>) {
  return <option data-slot="native-select-option" {...props} />;
}

/**
 * An option group element for organizing options within a `NativeSelect`.
 *
 * ### Component Props
 *
 * Accepts all standard `<optgroup>` HTML element props.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <NativeSelectOptGroup label="Fruits">
 *   <NativeSelectOption value="apple">Apple</NativeSelectOption>
 *   <NativeSelectOption value="banana">Banana</NativeSelectOption>
 * </NativeSelectOptGroup>
 * ```
 */
function NativeSelectOptGroup({
  className,
  ...props
}: React.ComponentProps<'optgroup'>) {
  return (
    <optgroup
      data-slot="native-select-optgroup"
      className={cn(className)}
      {...props}
    />
  );
}

export {NativeSelect, NativeSelectOptGroup, NativeSelectOption};
